from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check mailbox'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found'}

    try:
        with open(mailbox_path) as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse mailbox.json: {e}'}

    emails = data.get('emails', [])
    # Identify outbound emails to Nzinga by from_addr (not folder, since the agent may move emails to case folders).
    # An email is 'sent' if it was authored by someone other than Nzinga and addressed to Nzinga.
    sent_to_nzinga = [
        e for e in emails
        if 'p.nzinga@ridgelinegear.com' in (e.get('to_addr', '') or '')
        and 'p.nzinga@ridgelinegear.com' not in (e.get('from_addr', '') or '').lower()
        and (e.get('from_addr', '') or '').strip() != ''
    ]

    if not sent_to_nzinga:
        return {'pass': False, 'score': 0.0, 'feedback': 'No sent emails to p.nzinga@ridgelinegear.com found'}

    # Look for the template 3 email (ineligibility/denial) with WH-381 and CC to r.okafor
    found = False
    for e in sent_to_nzinga:
        body = (e.get('body_text', '') or '').lower()
        subject = (e.get('subject', '') or '').lower()
        cc = (e.get('cc_addr', '') or '').lower()
        attachments = e.get('attachments', []) or []
        att_names = ' '.join(str(a).lower() for a in attachments)

        has_cc_okafor = 'r.okafor@ridgelinegear.com' in cc
        has_wh381 = 'wh-381' in att_names or 'wh381' in att_names or 'wh_381' in att_names
        # Template 3 likely references ineligibility/denial
        has_template3_content = (
            'template 3' in body or 'template3' in body or
            'inelig' in body or 'denied' in body or 'not eligible' in body or
            'inelig' in subject or 'denied' in subject or
            'wh-381' in body or 'wh381' in body
        )

        if has_cc_okafor and has_wh381:
            found = True
            break
        # More lenient: cc + template 3 content
        if has_cc_okafor and has_template3_content:
            found = True
            break

    if not found:
        details = [f"Email {i}: CC={e.get('cc_addr')}, attachments={e.get('attachments')}, subject={e.get('subject')}" for i, e in enumerate(sent_to_nzinga)]
        return {'pass': False, 'score': 0.0, 'feedback': f'No sent email to p.nzinga@ridgelinegear.com with CC to r.okafor@ridgelinegear.com and WH-381 attachment found. Emails found: {details}'}

    return {'pass': True, 'score': 1.0, 'feedback': 'Found sent email to p.nzinga@ridgelinegear.com with CC to r.okafor@ridgelinegear.com and WH-381 attachment.'}

