from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    # Check for WH-381 in workspace files
    workspace = Path(workspace_path)

    # Search for WH-381 file with various extensions
    wh381_files = []
    for pattern in ['*WH-381*', '*WH381*', '*wh-381*', '*wh381*', '*wh_381*']:
        wh381_files.extend(workspace.glob(f'**/{pattern}'))

    # Also check attachments or email-related folders
    if not wh381_files:
        # Check if it might be referenced in any file
        all_files = list(workspace.glob('**/*'))
        for f in all_files:
            if 'wh' in f.name.lower() and ('381' in f.name):
                wh381_files.append(f)

    # Check external services for the attachment
    if not wh381_files and external_services_path:
        mailbox_path = Path(external_services_path) / 'mailbox.json'
        if mailbox_path.exists():
            import json
            try:
                with open(mailbox_path) as f:
                    data = json.load(f)
                emails = data.get('emails', [])
                for e in emails:
                    if e.get('folder', '').lower() == 'sent':
                        attachments = e.get('attachments', []) or []
                        for att in attachments:
                            att_str = str(att).lower()
                            if 'wh-381' in att_str or 'wh381' in att_str or 'wh_381' in att_str:
                                # Found as an attachment in a sent email
                                # Check the attachment content if available
                                body = (e.get('body_text', '') or '').lower()
                                has_part_a = 'part a' in body or 'parta' in body
                                has_ineligible = 'not eligible' in body or 'ineligible' in body
                                if has_part_a or has_ineligible:
                                    return {'pass': True, 'score': 1.0, 'feedback': f'WH-381 found as attachment in sent email with Part A / ineligibility indicators.'}
                                # If attachment exists in sent email, that's likely sufficient
                                return {'pass': True, 'score': 1.0, 'feedback': f'WH-381 found as attachment in sent email.'}
            except Exception:
                pass

    if not wh381_files:
        # Final check: look in any PDF or docx files for WH-381 content
        found_content = False
        for ext in ['*.pdf', '*.docx', '*.doc']:
            for f in workspace.glob(f'**/{ext}'):
                fname = f.name.lower()
                if 'wh' in fname or '381' in fname:
                    wh381_files.append(f)
                    found_content = True

        if not wh381_files:
            return {'pass': False, 'score': 0.0, 'feedback': 'No WH-381 form file found in workspace or mailbox attachments'}

    # Try to read content from found files
    for f in wh381_files:
        content = ''
        try:
            if f.suffix.lower() == '.pdf':
                import pdfplumber
                with pdfplumber.open(f) as pdf:
                    content = ' '.join(page.extract_text() or '' for page in pdf.pages).lower()
            elif f.suffix.lower() in ['.docx']:
                from docx import Document
                doc = Document(f)
                content = ' '.join(p.text for p in doc.paragraphs).lower()
            elif f.suffix.lower() in ['.txt', '.html', '.htm']:
                content = f.read_text(errors='ignore').lower()
            else:
                content = f.name.lower()  # At minimum check filename
        except Exception:
            content = f.name.lower()

        has_part_a = 'part a' in content or 'section 1' in content or 'employer' in content
        has_ineligible = 'not eligible' in content or 'ineligible' in content or 'you are not eligible' in content

        if has_part_a and has_ineligible:
            return {'pass': True, 'score': 1.0, 'feedback': f'WH-381 found at {f} with Part A filled out and "not eligible" indication.'}

        # If we found the file but couldn't verify content, give partial pass
        if 'wh-381' in f.name.lower() or 'wh381' in f.name.lower():
            return {'pass': True, 'score': 0.8, 'feedback': f'WH-381 file found at {f}; could not fully verify Part A and ineligibility marking from content.'}

    return {'pass': False, 'score': 0.0, 'feedback': f'WH-381 files found ({wh381_files}) but could not verify Part A filled out and "not eligible" marking.'}

from pathlib import Path
import json
import re
import openpyxl

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check Slack'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    try:
        with open(slack_path) as f:
            slack_data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse slack_data.json: {e}'}

    # Get FMLA Case ID from leave_tracker
    fmla_case_id = None
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    leave_tracker = None
    for f in xlsx_files:
        if 'leave' in f.name.lower() and 'tracker' in f.name.lower():
            leave_tracker = f
            break
    if leave_tracker is None:
        for f in xlsx_files:
            if 'leave' in f.name.lower():
                leave_tracker = f
                break

    if leave_tracker:
        try:
            wb = openpyxl.load_workbook(leave_tracker)
            ws = wb.active
            headers = []
            for i, row in enumerate(ws.iter_rows(values_only=True)):
                if i == 0:
                    headers = [str(c).strip().lower() if c else '' for c in row]
                    break
            case_col = None
            for idx, h in enumerate(headers):
                if 'case' in h and ('id' in h or 'num' in h or 'no' in h):
                    case_col = idx
                    break
            if case_col is None:
                for idx, h in enumerate(headers):
                    if 'case' in h:
                        case_col = idx
                        break
            leave_type_col = None
            for idx, h in enumerate(headers):
                if 'leave type' in h or 'leave_type' in h:
                    leave_type_col = idx
                    break
            if leave_type_col is None:
                for idx, h in enumerate(headers):
                    if 'type' in h:
                        leave_type_col = idx
                        break

            for i, row in enumerate(ws.iter_rows(values_only=True)):
                if i == 0:
                    continue
                row_str = ' '.join(str(c).lower() for c in row if c is not None)
                lt = str(row[leave_type_col]).strip().lower() if (leave_type_col is not None and leave_type_col < len(row) and row[leave_type_col] is not None) else ''
                if ('nzinga' in row_str or '1222' in row_str) and 'fmla' in row_str and 'famli' not in lt:
                    if case_col is not None and case_col < len(row) and row[case_col]:
                        fmla_case_id = str(row[case_col]).strip()
                    else:
                        # Try to extract from row
                        cases = re.findall(r'[A-Za-z]{2,5}-?\d{4,}', ' '.join(str(c) for c in row if c is not None))
                        if cases:
                            fmla_case_id = cases[0]
                    break
        except Exception:
            pass

    # Find #leave-intake channel
    channels = slack_data.get('channels', {})
    leave_intake_channel_id = None
    for ch_id, ch_data in channels.items():
        if 'leave' in ch_data.get('name', '').lower() and 'intake' in ch_data.get('name', '').lower():
            leave_intake_channel_id = ch_id
            break
    if leave_intake_channel_id is None:
        for ch_id, ch_data in channels.items():
            if 'leave' in ch_data.get('name', '').lower():
                leave_intake_channel_id = ch_id
                break

    if leave_intake_channel_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': '#leave-intake channel not found in Slack'}

    messages = slack_data.get('messages', {})
    channel_messages = messages.get(leave_intake_channel_id, [])

    found = False
    for msg in channel_messages:
        text = (msg.get('text', '') or '').upper()
        if 'FMLA DENIED (INELIGIBILITY)' in text or 'FMLA DENIED' in text:
            # Check for case ID match
            has_case_id = True  # Default True if we couldn't get case ID
            if fmla_case_id:
                has_case_id = fmla_case_id.upper() in text
            # Check for hours reference
            text_lower = msg.get('text', '').lower()
            has_hours = 'hour' in text_lower
            if has_case_id and has_hours:
                found = True
                break
            elif has_case_id:
                # Slightly lenient: if we found case ID, accept even without explicit 'hours' word
                found = True
                break

    if not found:
        all_texts = [msg.get('text', '')[:100] for msg in channel_messages]
        return {'pass': False, 'score': 0.0, 'feedback': f'No Slack message in #leave-intake with FMLA DENIED (INELIGIBILITY) + Case ID ({fmla_case_id}) + hours found. Messages: {all_texts}'}

    return {'pass': True, 'score': 1.0, 'feedback': f'Found Slack message in #leave-intake with FMLA DENIED (INELIGIBILITY) and Case ID ({fmla_case_id}) and hours reference.'}

